export default {
  async fetch(request) {
    const body = JSON.stringify({ hello: "world" });
    return new Response(body, {
      headers: {
        "Content-Type": "application/json",
        // Browser keeps it 1h; Cloudflare edge keeps it 1 day
        "Cache-Control": "public, max-age=3600, s-maxage=86400"
      }
    });
  }
};
